import React, { useState } from 'react';
import { Button, Select, DateRangeFilter, Modal, Input, addToast } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { sxService } from '../../../services/sx/sxService';
import type { StageTrackingDto } from '../../../services/sx/models';
import { formatDateLocal, formatNumber } from '../../../utils/format';
import styles from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const PAGE_SIZE = 50;

const STATUS_OPTIONS = [
  { value: '', label: 'Tất cả' },
  { value: 'Pending', label: 'Chờ QC' },
  { value: 'QcApproved', label: 'Đã duyệt' },
  { value: 'QcRejected', label: 'Từ chối' },
];

const SanPhamHoanThanhPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const now = new Date();
  const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().slice(0, 10);
  const monthEnd = now.toISOString().slice(0, 10);

  const [fromDate, setFromDate] = useState(monthStart);
  const [toDate, setToDate] = useState(monthEnd);
  const [status, setStatus] = useState('');
  const [rows, setRows] = useState<StageTrackingDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [rejectOpen, setRejectOpen] = useState(false);
  const [target, setTarget] = useState<StageTrackingDto | null>(null);
  const [rejectReason, setRejectReason] = useState('');
  const [actionId, setActionId] = useState<string | null>(null);

  const load = () => {
    setLoading(true);
    sxService
      .getStageTracking({ fromDate, toDate, status: status || undefined, page: 1, pageSize: PAGE_SIZE })
      .then(res => setRows(res.items))
      .catch(err => dispatch(addToast({ message: err?.message ?? 'Lỗi tải dữ liệu', type: 'error' })))
      .finally(() => setLoading(false));
  };
  const handleSearch = () => setReloadKey(k => k + 1);
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [fromDate, toDate, status]);

  const handleApprove = async (id: string) => {
    setActionId(id);
    try {
      await sxService.qcApproveStageTracking(id);
      dispatch(addToast({ message: 'QC duyệt thành công', type: 'success' }));
      load();
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Duyệt thất bại', type: 'error' }));
    } finally {
      setActionId(null);
    }
  };

  const handleReject = async () => {
    if (!target || !rejectReason.trim()) {
      dispatch(addToast({ message: 'Vui lòng nhập lý do từ chối', type: 'error' }));
      return;
    }
    setActionId(target.id);
    try {
      await sxService.qcRejectStageTracking(target.id, rejectReason.trim());
      dispatch(addToast({ message: 'Từ chối phiếu thành công', type: 'success' }));
      setRejectOpen(false);
      setRejectReason('');
      load();
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Từ chối thất bại', type: 'error' }));
    } finally {
      setActionId(null);
    }
  };

  const totalOut = rows.reduce((a, r) => a + r.outQty, 0);
  const totalDefect = rows.reduce((a, r) => a + r.defectQty, 0);
  const pending = rows.filter(r => r.status === 'Pending').length;

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-check-circle" /> Sản phẩm hoàn thành</h1>
        </div>
      </div>

      <div className={styles.filtersBar} data-testid={`erp-san-pham-hoan-thanh-filters`}>
        <DateRangeFilter
          fromDate={fromDate}
          toDate={toDate}
          onChange={(v: DateRangeValue) => { setFromDate(v.fromDate ?? ''); setToDate(v.toDate ?? ''); }}
        />
        <Select value={status} onChange={e => setStatus(e.target.value)} options={STATUS_OPTIONS} size="small" />
      </div>

      <div className={styles.summaryBar}>
        <div className={styles.summaryItem}><label className={styles.label}>SL ra</label><strong>{formatNumber(totalOut)}</strong></div>
        <div className={styles.summaryItem}><label className={styles.label}>SL lỗi</label><strong>{formatNumber(totalDefect)}</strong></div>
        <div className={styles.summaryItem}><label className={styles.label}>Chờ QC</label><strong>{pending}</strong></div>
        <ListSearchRefreshButtons testIdPrefix="erp-san-pham-hoan-thanh" onSearch={handleSearch} onRefresh={refresh} showSearch={false} />
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : rows.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Chưa có phiếu theo dõi</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Ngày</th>
                  <th>LSX</th>
                  <th>Công đoạn</th>
                  <th className={styles.colRight}>SL ra</th>
                  <th className={styles.colRight}>SL lỗi</th>
                  <th>Trạng thái</th>
                  <th className={styles.colActions}></th>
                </tr>
              </thead>
              <tbody>
                {rows.map(r => (
                  <tr key={r.id} className={r.status === 'Pending' ? styles.rowDanger : undefined}>
                    <td>{formatDateLocal(r.trackingDate)}</td>
                    <td><code>{r.productionOrderCode}</code></td>
                    <td>{r.stageName}</td>
                    <td className={styles.colRight}>{formatNumber(r.outQty)}</td>
                    <td className={styles.colRight}>{formatNumber(r.defectQty)}</td>
                    <td>
                      <span className={
                        r.status === 'QcApproved' ? styles.tagSuccess :
                        r.status === 'QcRejected' ? styles.tagError : styles.tagWarning
                      }>
                        {STATUS_OPTIONS.find(o => o.value === r.status)?.label ?? r.status}
                      </span>
                    </td>
                    <td className={styles.colActions}>
                      {r.status === 'Pending' && (
                        <>
                          <button type="button" className={styles.actionBtn} disabled={actionId === r.id} onClick={() => handleApprove(r.id)} title="Duyệt">
                            <i className="fas fa-check" />
                          </button>
                          <button type="button" className={`${styles.actionBtn} ${styles.actionBtnDanger}`} onClick={() => { setTarget(r); setRejectOpen(true); }} title="Từ chối">
                            <i className="fas fa-times" />
                          </button>
                        </>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      <Modal isOpen={rejectOpen} onClose={() => setRejectOpen(false)} title="Từ chối phiếu sản lượng">
        <div className={styles.modalBody}>
          <p>LSX: <b>{target?.productionOrderCode}</b> — {target?.stageName}</p>
          <div className={styles.field}>
            <label className={styles.label}>Lý do *</label>
            <textarea value={rejectReason} onChange={e => setRejectReason(e.target.value)} rows={3} />
          </div>
        </div>
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={() => setRejectOpen(false)}>Huỷ</Button>
          <Button variant="primary" onClick={handleReject} disabled={actionId === target?.id}>Từ chối</Button>
        </div>
      </Modal>
    </div>
  );
};

export default SanPhamHoanThanhPage;
